const body = $input.first().json.body || $input.first().json;

// 1. Verifica se o objeto de mensagem existe
if (!body?.message) return [];

// 2. Ignora mensagens de grupo
if (body.message.isGroup === true) return [];

// 3. Extrai o número de telefone
const rawPhone = body.message.sender_pn || body.chat?.phone || '';
const phone = rawPhone.replace('@s.whatsapp.net', '').replace(/\D/g, '');

// 4. Extrai o texto da mensagem
const message = body.message.text || body.message.content || '';

// 5. Extrai nome do contato e instância
const name = body.message.senderName || body.chat?.wa_name || 'Desconhecido';
const instance = body.instanceName || '';

// 6. Se não tiver telefone ou mensagem, encerra
if (!phone || !message.trim()) return [];

return [{ 
  json: { 
    phone, 
    message: message.trim(), 
    name, 
    instance 
  } 
}];

// Busca empresa pela instância — suporta multi-instância via company_instances
// Tenta primeiro na tabela nova company_instances, fallback para company_integrations
const instance = $json.instance;
return [{ json: { ...$json, _lookup_instance: instance } }];

// Resolve qual fonte de instância usar (nova tabela company_instances ou legado company_integrations)
const extracted = $('Extrair Dados da Mensagem').first().json;

let company_id, uazapi_token, uazapi_base_url, uazapi_instance, webhook_secret;

// Tenta multi-instância (nova tabela)
try {
  const nova = $('Buscar Instância (Multi)').first().json;
  const novaArr = Array.isArray(nova) ? nova : [nova];
  if (novaArr[0]?.company_id) {
    // Busca uazapi_base_url na tabela de integrations usando company_id
    company_id = novaArr[0].company_id;
    uazapi_token = novaArr[0].uazapi_token;
    uazapi_instance = novaArr[0].instance_name;
    uazapi_base_url = null; // será resolvido abaixo via legado
  }
} catch(e) {}

// Tenta legado (company_integrations)
try {
  const leg = $('Buscar Instância (Legado)').first().json;
  const legArr = Array.isArray(leg) ? leg : [leg];
  if (legArr[0]?.company_id) {
    if (!company_id) company_id = legArr[0].company_id;
    if (!uazapi_token) uazapi_token = legArr[0].uazapi_token;
    if (!uazapi_instance) uazapi_instance = legArr[0].uazapi_instance;
    uazapi_base_url = legArr[0].uazapi_base_url;
    webhook_secret = legArr[0].webhook_secret;
  }
} catch(e) {}

if (!company_id) return [];

return [{ json: { 
  ...extracted, 
  company_id, 
  uazapi_base_url: uazapi_base_url || 'https://free.uazapi.com',
  uazapi_token, 
  uazapi_instance, 
  webhook_secret: webhook_secret || ''
}}];

const ctx = $('Resolver Instância').first().json;
const settings = $('Buscar Configurações').first().json;
const company = $('Buscar Dados da Empresa').first().json;

const sd = Array.isArray(settings) ? settings[0] : settings;
const cd = Array.isArray(company) ? company[0] : company;

const openingHours = sd?.opening_hours || {};
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dayMap = ['sun','mon','tue','wed','thu','fri','sat'];
const dayKey = dayMap[now.getDay()];
const todayConfig = openingHours[dayKey];
let inHours = true;

if (todayConfig) {
  if (!todayConfig.active) { inHours = false; }
  else {
    const [oh,om] = (todayConfig.open||'08:00').split(':').map(Number);
    const [ch,cm] = (todayConfig.close||'18:00').split(':').map(Number);
    const cur = now.getHours()*60+now.getMinutes();
    inHours = cur >= oh*60+om && cur <= ch*60+cm;
  }
}

return [{ json: { 
  ...ctx, 
  company_name: cd?.name || 'Empresa',
  welcome_message: sd?.welcome_message || 'Olá! Como posso ajudar?',
  fallback_message: sd?.fallback_message || 'Não entendi. Pode repetir?',
  off_hours_message: sd?.off_hours_message || 'Estamos fora do horário de atendimento.',
  ai_persona: sd?.ai_persona || null,
  ai_tone: sd?.ai_tone || 'amigavel',
  ai_expertise: sd?.ai_expertise || null,
  ai_extra_context: sd?.ai_extra_context || null,
  ai_restrictions: sd?.ai_restrictions || null,
  inHours
}}];

let lead;
try { const c = $('Criar Novo Lead').first().json; lead = Array.isArray(c) ? c[0] : c; }
catch { const f = $('Buscar Lead').first().json; lead = Array.isArray(f) ? f[0] : f; }
const ctx = $('Resolver Instância').first().json;
const hr = $('Verificar Horário e Montar Dados').first().json;
return [{ json: { 
  ...ctx, 
  company_name: hr.company_name, 
  welcome_message: hr.welcome_message, 
  fallback_message: hr.fallback_message,
  ai_persona: hr.ai_persona,
  ai_tone: hr.ai_tone,
  ai_expertise: hr.ai_expertise,
  ai_extra_context: hr.ai_extra_context,
  ai_restrictions: hr.ai_restrictions,
  lead_id: lead.id, 
  lead_name: lead.name, 
  lead_status: lead.current_status, 
  is_new_lead: lead.current_status === 'new' 
}}];

let cid, active_flow_id = null, current_flow_step_id = null, isNewConversation = false;

try {
  const c = $('Criar Nova Conversa').first().json;
  const arr = Array.isArray(c) ? c : [c];
  cid = arr[0].id;
  isNewConversation = true;
} catch {
  const f = $('Buscar Conversa Ativa').first().json;
  const arr = Array.isArray(f) ? f : [f];
  cid = arr[0].id;
  active_flow_id = arr[0].active_flow_id;
  current_flow_step_id = arr[0].current_flow_step_id;
  isNewConversation = false;
}

return [{ json: { 
  ...$('Consolidar Lead').first().json, 
  conversation_id: cid, 
  active_flow_id,
  current_flow_step_id,
  is_new_conversation: isNewConversation 
}}];

// STATE MACHINE ROUTER v6
// Prioridade: 1=active_flow, 2=first_message, 3=keyword, 4=IA

const ctx = $('Consolidar Conversa').first().json;
const allItems = $input.all();
const flows = allItems.map(i => i.json).filter(f => f && f.id);
const msgLower = String(ctx.message || '').toLowerCase().trim();

// PRIORIDADE 1: Fluxo em andamento
if (ctx.active_flow_id) {
  const activeFlow = flows.find(f => f.id === ctx.active_flow_id);
  if (activeFlow) {
    const steps = Array.isArray(activeFlow.steps)
      ? activeFlow.steps.sort((a, b) => a.step_order - b.step_order) : [];
    return [{ json: { ...ctx, active_flow: activeFlow, all_flows: flows, flow_steps: steps, use_ai: false, is_continuing: true } }];
  }
}

// PRIORIDADE 2 e 3: Novo fluxo por trigger
const sorted = [...flows].sort((a, b) => (a.priority || 10) - (b.priority || 10));

for (const flow of sorted) {
  const keywords = flow.trigger_keywords || [];
  const triggerType = flow.trigger_type || 'keyword';
  const steps = Array.isArray(flow.steps) ? flow.steps.sort((a, b) => a.step_order - b.step_order) : [];
  if (steps.length === 0) continue;

  if (triggerType === 'first_message') {
    if (ctx.is_new_conversation === true && ctx.is_new_lead === true) {
      return [{ json: { ...ctx, active_flow: flow, all_flows: flows, flow_steps: steps, use_ai: false, is_continuing: false } }];
    }
    continue;
  }

  if (triggerType === 'keyword' && keywords.length > 0) {
    const hit = keywords.some(kw => msgLower.includes(String(kw).toLowerCase().trim()));
    if (hit) {
      return [{ json: { ...ctx, active_flow: flow, all_flows: flows, flow_steps: steps, use_ai: false, is_continuing: false } }];
    }
  }
}

// PRIORIDADE 4: IA
return [{ json: { ...ctx, active_flow: null, all_flows: flows, flow_steps: [], use_ai: true, is_continuing: false } }];

// TEMPLATE ROUTER v6
// Se o fluxo ativo é um template, roteia para o path dedicado.
// Fluxos custom caem no engine genérico.

const ctx = $json;
const flow = ctx.active_flow || {};
const slug = flow.template_slug || null;

// Passa o slug para o próximo nó decidir
return [{ json: { ...ctx, resolved_template_slug: slug } }];

// PATH: COLETA DE CONTATO
// Verifica qual campo já foi coletado e envia a próxima pergunta.

const ctx = $json;
const flow = ctx.active_flow || {};
const config = flow.config || {};
const isContinuing = ctx.is_continuing;
const metadata = ctx.metadata || {};

// Campos a coletar (ordem definida no config ou padrão)
const fields = config.fields || [
  { key: 'name', question: 'Qual é o seu nome completo?', save_to: 'lead_name' },
  { key: 'email', question: 'Qual é o seu e-mail?', save_to: 'lead_email' },
  { key: 'interest', question: 'O que você procura?', save_to: 'lead_interest' }
];

// Simulated state via conversation metadata (stored in flow_step)
const collectedFields = ctx.collected_fields || {};

// Encontra o próximo campo a coletar
const nextField = fields.find(f => !collectedFields[f.key]);

if (!nextField) {
  // Todos coletados
  const completionMsg = config.completion_message || 
    `Obrigado! Suas informações foram registradas. Em breve entraremos em contato. 😊`;
  return [{ json: {
    ...ctx,
    messages_to_send: [completionMsg],
    new_active_flow_id: null,
    new_current_step_id: null,
    flow_ended: true,
    flow_executed: true,
    collected_fields: collectedFields
  }}];
}

// Se está continuando, salva a resposta do campo anterior
if (isContinuing && ctx.current_flow_step_id) {
  const prevField = fields[fields.indexOf(nextField) - 1];
  if (prevField) collectedFields[prevField.key] = ctx.message;
}

// Verifica se agora todos foram coletados após salvar
const stillPending = fields.find(f => !collectedFields[f.key]);
if (!stillPending) {
  const completionMsg = config.completion_message || `Obrigado! Dados registrados com sucesso. 😊`;
  return [{ json: {
    ...ctx,
    messages_to_send: [completionMsg],
    new_active_flow_id: null,
    new_current_step_id: null,
    flow_ended: true,
    flow_executed: true,
    collected_fields: collectedFields
  }}];
}

// Ainda tem campos — envia a próxima pergunta e pausa
return [{ json: {
  ...ctx,
  messages_to_send: [stillPending.question],
  new_active_flow_id: flow.id,
  new_current_step_id: 'coleta_' + stillPending.key,
  flow_ended: false,
  flow_executed: true,
  collected_fields: collectedFields
}}];

// PATH: AGENDAMENTO
// Busca horários disponíveis e gerencia o fluxo de agendamento.

const ctx = $json;
const flow = ctx.active_flow || {};
const config = flow.config || {};
const isContinuing = ctx.is_continuing;
const userMessage = String(ctx.message || '').trim();

// Se está continuando, o usuário digitou uma opção de horário
if (isContinuing && ctx.current_flow_step_id === 'agendamento_escolha') {
  const num = parseInt(userMessage);
  const slots = ctx.available_slots || [];

  if (!isNaN(num) && num >= 1 && num <= slots.length) {
    const chosen = slots[num - 1];
    const confirmMsg = config.confirm_message 
      ? config.confirm_message.replace('{{slot}}', chosen)
      : `✅ Agendamento confirmado para: *${chosen}*\n\nSalvaremos seu horário. Qualquer dúvida, é só falar!`;

    return [{ json: {
      ...ctx,
      messages_to_send: [confirmMsg],
      new_active_flow_id: null,
      new_current_step_id: null,
      flow_ended: true,
      flow_executed: true,
      chosen_slot: chosen,
      should_create_appointment: true
    }}];
  } else {
    return [{ json: {
      ...ctx,
      messages_to_send: ['Opção inválida. Por favor, digite apenas o número correspondente ao horário desejado.'],
      new_active_flow_id: flow.id,
      new_current_step_id: 'agendamento_escolha',
      flow_ended: false,
      flow_executed: true
    }}];
  }
}

// Gera slots disponíveis para os próximos dias
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const slots = [];
const maxDays = config.max_advance_days || 7;
const sessionDuration = config.session_duration || 60;
const startHour = config.start_hour || 9;
const endHour = config.end_hour || 18;

const dayNames = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
const monthNames = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];

for (let d = 1; d <= maxDays && slots.length < 6; d++) {
  const date = new Date(now);
  date.setDate(date.getDate() + d);
  if (date.getDay() === 0) continue; // Pula domingo

  for (let h = startHour; h < endHour && slots.length < 6; h++) {
    slots.push(`${dayNames[date.getDay()]}, ${String(date.getDate()).padStart(2,'0')} ${monthNames[date.getMonth()]} às ${String(h).padStart(2,'0')}:00`);
  }
}

if (slots.length === 0) {
  return [{ json: {
    ...ctx,
    messages_to_send: ['Desculpe, não há horários disponíveis no momento. Entre em contato diretamente conosco.'],
    new_active_flow_id: null,
    new_current_step_id: null,
    flow_ended: true,
    flow_executed: true
  }}];
}

const intro = config.intro_message || '📅 Escolha um horário disponível:';
const slotList = slots.map((s, i) => `${i + 1}. ${s}`).join('\n');

return [{ json: {
  ...ctx,
  messages_to_send: [`${intro}\n\n${slotList}\n\nDigite o número do horário desejado.`],
  new_active_flow_id: flow.id,
  new_current_step_id: 'agendamento_escolha',
  flow_ended: false,
  flow_executed: true,
  available_slots: slots
}}];

// PATH: CATÁLOGO INTERATIVO
// Busca produtos e formata a lista de forma rica.

const ctx = $json;
const flow = ctx.active_flow || {};
const config = flow.config || {};

// Usa produtos já disponíveis no contexto ou busca
let productsRaw = [];
try {
  const raw = $('Buscar Produtos para Catálogo').all();
  productsRaw = raw.map(i => i.json).filter(p => p && p.name);
} catch(e) { productsRaw = []; }

let catalogText;
if (productsRaw.length === 0) {
  catalogText = 'Nenhum produto cadastrado no momento.';
} else {
  catalogText = productsRaw.map((p, i) => {
    let line = `${i + 1}. *${p.name}*`;
    if (p.description) line += `\n   ${p.description}`;
    if (p.price) line += `\n   💰 R$ ${parseFloat(p.price).toFixed(2)}`;
    return line;
  }).join('\n\n');
}

const introMsg = config.intro_message || '🛍️ Confira nosso catálogo:';
const followupMsg = config.followup_message || null;

const messages = [`${introMsg}\n\n${catalogText}`];
if (followupMsg) messages.push(followupMsg);

return [{ json: {
  ...ctx,
  messages_to_send: messages,
  new_active_flow_id: null,
  new_current_step_id: null,
  flow_ended: true,
  flow_executed: true
}}];

// ENGINE GENÉRICO v5 — mantido intacto para fluxos custom
// (message, question, condition, catalog, end)

const ctx = $json;
const allFlows = Array.isArray(ctx.all_flows) ? ctx.all_flows : [];

let productsRaw = [];
try { 
  const raw = $('Buscar Produtos IA').all();
  productsRaw = raw.map(i => i.json).filter(p => p && p.name);
} catch(e) { productsRaw = []; }

const productsList = productsRaw.length > 0
  ? productsRaw.map((p, i) => {
      let line = (i + 1) + '. ' + p.name;
      if (p.description) line += ' - ' + p.description;
      if (p.price) line += ' (R$ ' + parseFloat(p.price).toFixed(2) + ')';
      return line;
    }).join('\n')
  : 'Nenhum produto cadastrado ainda.';

let steps = Array.isArray(ctx.flow_steps) ? ctx.flow_steps : [];
let flow = ctx.active_flow || {};
let config = flow.config || {};
let isContinuing = ctx.is_continuing === true;
let currentStepId = ctx.current_flow_step_id || null;
let userMessage = String(ctx.message || '').trim();
let startIndex = 0;
let messagesToSend = [];
let pausedAtStep = null;
let ended = false;
let newActiveFlowId = flow.id || null;

if (isContinuing && currentStepId) {
  const currentIdx = steps.findIndex(s => s.id === currentStepId);
  if (currentIdx >= 0) {
    const pausedStep = steps[currentIdx];
    if (pausedStep.step_type === 'condition') {
      const routes = (pausedStep.metadata && pausedStep.metadata.routes) ? pausedStep.metadata.routes : {};
      let matchedFlowId = null;
      for (const [key, targetId] of Object.entries(routes)) {
        if (userMessage.toLowerCase() === String(key).toLowerCase()) { matchedFlowId = targetId; break; }
      }
      if (matchedFlowId) {
        const targetFlow = allFlows.find(f => f.id === matchedFlowId);
        if (targetFlow) {
          flow = targetFlow; config = flow.config || {};
          steps = Array.isArray(targetFlow.steps) ? targetFlow.steps.sort((a, b) => a.step_order - b.step_order) : [];
          startIndex = 0; newActiveFlowId = targetFlow.id;
        } else {
          messagesToSend.push('Esta opção não está disponível. Tente novamente.');
          pausedAtStep = pausedStep; startIndex = steps.length;
        }
      } else {
        messagesToSend.push('Opção inválida. Digite apenas o número correspondente.');
        pausedAtStep = pausedStep; startIndex = steps.length;
      }
    } else if (pausedStep.step_type === 'question') { startIndex = currentIdx + 1; }
    else { startIndex = currentIdx + 1; }
  }
}

function interpolate(text) {
  let s = String(text || '');
  for (const [k, v] of Object.entries(config)) s = s.replace(new RegExp('{{' + k + '}}', 'g'), String(v != null ? v : ''));
  return s
    .replace(/{{products_list}}/g, productsList)
    .replace(/{{company_name}}/g, ctx.company_name || '')
    .replace(/{{lead_name}}/g, ctx.lead_name || ctx.name || 'Cliente')
    .replace(/{{nome}}/g, ctx.lead_name || ctx.name || 'Cliente')
    .replace(/{{phone}}/g, ctx.phone || '');
}

for (let i = startIndex; i < steps.length; i++) {
  const step = steps[i];
  if (step.step_type === 'end') { ended = true; const c = interpolate(step.message); if (c.trim()) messagesToSend.push(c); break; }
  const content = interpolate(step.message);
  if (content.trim()) messagesToSend.push(content);
  if (['question', 'catalog', 'condition'].includes(step.step_type)) { pausedAtStep = step; break; }
}

return [{ json: {
  ...ctx,
  products_list: productsList,
  messages_to_send: messagesToSend,
  new_active_flow_id: ended ? null : (newActiveFlowId || null),
  new_current_step_id: pausedAtStep ? pausedAtStep.id : null,
  flow_ended: ended,
  flow_executed: true
}}];

const ctx = $('Consolidar Conversa').first().json;
const historyRaw = $('Buscar Histórico').first().json;
const faqsRaw = $('Buscar FAQs').first().json;
const productsRaw = $('Buscar Produtos IA').first().json;

const history = (Array.isArray(historyRaw) ? historyRaw : []).reverse();
const faqs = Array.isArray(faqsRaw) ? faqsRaw : [];
const products = Array.isArray(productsRaw) ? productsRaw : [];

const faqCtx = faqs.length > 0 
  ? faqs.map(f => `P: ${f.question}\nR: ${f.answer}`).join('\n\n') 
  : 'Nenhuma FAQ cadastrada.';

const prodCtx = products.length > 0 
  ? products.map(p => { let l = `- ${p.name}`; if (p.description) l += `: ${p.description}`; if (p.price) l += ` (R$ ${parseFloat(p.price).toFixed(2)})`; return l; }).join('\n') 
  : 'Nenhum produto cadastrado.';

const histMsgs = history.map(m => ({ role: m.sender_type === 'bot' ? 'assistant' : 'user', content: String(m.content || '') }));

// Contexto da IA (novos campos v6)
const persona = ctx.ai_persona || `Você é um assistente de atendimento da empresa "${ctx.company_name}"`;

const toneMap = {
  formal: 'Mantenha um tom formal e profissional.',
  amigavel: 'Seja amigável, caloroso e próximo do cliente.',
  descontraido: 'Use um tom leve, descontraído e informal.',
  tecnico: 'Seja preciso, técnico e objetivo.'
};
const toneInstruction = toneMap[ctx.ai_tone] || toneMap['amigavel'];

const expertiseSection = ctx.ai_expertise ? `\nESPECIALIDADE:\n${ctx.ai_expertise}` : '';
const extraCtxSection = ctx.ai_extra_context ? `\nINFORMAÇÕES DA EMPRESA:\n${ctx.ai_extra_context}` : '';
const restrictionsSection = ctx.ai_restrictions ? `\nRESTRIÇÕES (NUNCA IGNORE):\n${ctx.ai_restrictions}` : '';

const systemPrompt = `${persona}. ${toneInstruction}

REGRAS GERAIS:
- Responda SEMPRE em português brasileiro
- Seja conciso (máximo 3 parágrafos)
- Use emojis com moderação
- NÃO invente informações não presentes abaixo
- Se não souber a resposta, use o fallback${expertiseSection}${extraCtxSection}

FAQ:
${faqCtx}

PRODUTOS/SERVIÇOS:
${prodCtx}${restrictionsSection}

FALLBACK: ${ctx.fallback_message || 'Um momento, vou te encaminhar para um atendente.'}`;

const messagesArray = [
  { role: 'system', content: systemPrompt },
  ...histMsgs,
  { role: 'user', content: String(ctx.message || '') }
];

const geminiPayload = {
  model: 'gemini-2.5-flash',
  messages: messagesArray,
  max_tokens: 600,
  temperature: 0.7
};

return [{ json: { ...ctx, systemPrompt, geminiPayload } }];

const r = $input.first().json;
const ctx = $('Montar Prompt para IA (v6)').first().json;
const reply = r?.choices?.[0]?.message?.content || ctx.fallback_message || 'Não consegui processar. Tente novamente.';
return [{ json: { ...ctx, reply } }];
